# Invoices and Other directories
INVOICES_DIR = '/app/invoices'
OTHER_DIR = '/app/other'

if not os.path.exists(INVOICES_DIR): os.makedirs(INVOICES_DIR)
if not os.path.exists(OTHER_DIR): os.makedirs(OTHER_DIR)

def parse_amount(val_str):
    val_str = val_str.replace(' ', '').replace('$', '').replace('€', '').replace('£', '').replace('USD', '')
    if ',' in val_str and '.' in val_str:
        val_str = val_str.replace(',', '')
    elif ',' in val_str:
        val_str = val_str.replace(',', '.')
    try:
        return float(val_str)
    except:
