results = []

for doc in os.listdir('/app/documents'):
    filepath = os.path.join('/app/documents', doc)
    text = get_text(filepath)

    # Check if invoice
    if 'invoice' in text.lower() or 'total' in text.lower() or 'tax id' in text.lower():
        # wait, some "other" might contain "total" - but let's be strict:
        # the stock report has no "invoice". Let's check keywords.
        is_invoice = False
        if 'invoice' in text.lower():
            is_invoice = True
        elif 'tax id' in text.lower() or 'totalprice' in text.lower() or 'total price' in text.lower() or 'gross worth' in text.lower() or 'amount due' in text.lower():
            is_invoice = True

        # Look at the text to avoid false positives.
        if 'Stock Report' in text:
            is_invoice = False

        if not is_invoice:
            shutil.move(filepath, os.path.join(OTHER_DIR, doc))
            continue

        print(f"Processing {doc}")

        # 1. Total extraction
        total_amount = None
        amount_due = None

        # Let's find matches for SubTotal, Total, Amount due, etc.
        # Stripe invoices
        total_match = re.search(r'Total:\s*\$?([\d\s,\.]+)', text)
        if total_match:
            total_amount = parse_amount(total_match.group(1))

        amount_due_match = re.search(r'Amount due:\s*\$?([\d\s,\.]+)', text)
        if amount_due_match:
            amount_due = parse_amount(amount_due_match.group(1))

        # PDF invoices (like wIQEB5nR79b2.pdf)
        if not total_amount:
            match = re.search(r'TotalPrice\s+([\d\.]+)', text)
            if match:
                total_amount = float(match.group(1))

            match = re.search(r'Total Price:\s*([\d\.]+)', text)
            if match:
                total_amount = float(match.group(1))

            match = re.search(r'Total:\s*([\d\.]+)', text)
            if match:
                total_amount = float(match.group(1))

        # Gross worth invoices (like vvK89XK847m3.jpg)
        if not total_amount:
            # Gross worth usually has the total at the very end
            match = re.findall(r'Gross\s*worth\s*\n+([\d\s,\.]+)\n+\$\s*([\d\s,\.]+)', text, re.IGNORECASE)
            if match:
                total_amount = parse_amount(match[-1][1])
            else:
                match = re.findall(r'Gross worth\s*\n+.*?\$\s*([\d\s,\.]+)', text, re.IGNORECASE)
                if match:
                    total_amount = parse_amount(match[-1])
                else:
                    # check "Total $ XXX $ YYY $ ZZZ"
                    match = re.search(r'Total\s+\$\s*([\d\s,\.]+)\s+\$\s*([\d\s,\.]+)\s+\$\s*([\d\s,\.]+)', text)
                    if match:
                        total_amount = parse_amount(match.group(3)) # Gross worth is the 3rd one

        if total_amount and amount_due and total_amount != amount_due:
            pass # Keep total_amount
        elif amount_due and not total_amount:
            total_amount = amount_due

        # 2. VAT extraction
        vat_amount = 0
        vat_match = re.findall(r'VAT\s*\n+([\d\s,\.]+)\n+\$\s*([\d\s,\.]+)', text)
        if vat_match:
            vat_amount = parse_amount(vat_match[-1][1])
        else:
            match = re.search(r'Total\s+\$\s*([\d\s,\.]+)\s+\$\s*([\d\s,\.]+)\s+\$\s*([\d\s,\.]+)', text)
            if match:
                vat_amount = parse_amount(match.group(2))

        # Stripe invoices often don't have VAT explicitly. Let's look for "Tax" or "GST"
        if not vat_amount:
            match = re.search(r'Tax:\s*\$?([\d\s,\.]+)', text)
            if match:
                vat_amount = parse_amount(match.group(1))

        print(f"  Total: {total_amount}, VAT: {vat_amount}")

    else:
        shutil.move(filepath, os.path.join(OTHER_DIR, doc))

